from pybricks.hubs import PrimeHub
from pybricks.parameters import Axis, Direction, Port, Stop
from pybricks.pupdevices import Motor
from pybricks.robotics import DriveBase
from pybricks.tools import StopWatch, multitask, run_task, wait

from utility import steer_turn, turn_by_wheel

# Set up all devices.
prime_hub = PrimeHub(top_side=Axis.Z, front_side=Axis.X)
watch = StopWatch()
rightsheel = Motor(Port.C, Direction.CLOCKWISE)
leftwheel = Motor(Port.D, Direction.COUNTERCLOCKWISE)
drive_base = DriveBase(leftwheel, rightsheel, 62.4, 80)
left_motor = Motor(Port.B, Direction.COUNTERCLOCKWISE)
right_motor = Motor(Port.F, Direction.COUNTERCLOCKWISE)

async def subtask():
    await left_motor.run_until_stalled(500, Stop.HOLD, 50)
    left_motor.reset_angle(0)

async def subtask2():
    await right_motor.run_until_stalled(500, Stop.HOLD, 50)
    right_motor.reset_angle(0)

async def subtask3():
    await drive_base.straight(-10)
    drive_base.reset(0, 0)
    drive_base.use_gyro(True)

async def subtask4():
    await drive_base.straight(60)
    await steer_turn(drive_base, leftwheel, rightsheel, 3, True)
    await drive_base.straight(80)

async def subtask5():
    await wait(500)
    await left_motor.run_target(150, 0)

async def subtask6():
    await wait(2000)
    await left_motor.run_until_stalled(200, Stop.HOLD, 50)

async def main():
    watch.reset()
    print('Battery', prime_hub.battery.voltage(), sep=", ")
    drive_base.use_gyro(True)
    await multitask(
        subtask(),
        subtask2(),
        subtask3(),
    )
    drive_base.settings(straight_speed=300)
    await drive_base.straight(400)
    # Mission 10 tip scale, hook up market roof.
    await left_motor.run_until_stalled(-300, Stop.HOLD, 60)
    print('Left motor limit', left_motor.angle())
    await multitask(
        drive_base.straight(-150),
        left_motor.run_angle(200, 120),
    )
    await multitask(
        subtask4(),
        subtask5(),
    )
    print('Heading before wares', drive_base.angle())
    # Mission 09 raise market wares.
    await drive_base.turn(-33)
    await drive_base.straight(-15)
    await steer_turn(drive_base, leftwheel, rightsheel, -32, False)
    await left_motor.run_until_stalled(-200, Stop.HOLD, 50)
    drive_base.settings(turn_rate=300)
    drive_base.settings(turn_acceleration=300)
    await multitask(
        drive_base.turn(-90),
        subtask6(),
        race=True,
    )
    drive_base.settings(turn_rate=300)
    drive_base.settings(turn_acceleration=600)
    await drive_base.straight(-10, then=Stop.NONE)
    await drive_base.turn(-20, then=Stop.NONE)
    await multitask(
        left_motor.run_target(500, 0),
        drive_base.straight(250),
    )
    print('Scale and pan', watch.time())


run_task(main())